import * as FileSystem from 'expo-file-system';

export const HABITS_FILE = `${FileSystem.documentDirectory}habits.json`;

const initialHabits = [
  {
    id: '1',
    title: 'Drink water regularly',
    frequency: 'daily',
    time: '08:00',
    goalDays: 30,
    done: false,
  },
  {
    id: '2',
    title: 'Brush teeth every night',
    frequency: 'daily',
    time: '22:00',
    goalDays: 30,
    done: false,
  },
  {
    id: '3',
    title: 'Go for a walk',
    frequency: 'weekly',
    time: '18:00',
    goalDays: 12,
    done: false,
  },
];

export async function ensureDatabase() {
  try {
    const fileInfo = await FileSystem.getInfoAsync(HABITS_FILE);
    if (!fileInfo.exists) {
      await FileSystem.writeAsStringAsync(
        HABITS_FILE,
        JSON.stringify(initialHabits),
        { encoding: FileSystem.EncodingType.UTF8 }
      );
    }
  } catch (error) {
    console.error('Error ensuring habits file:', error);
    throw error;
  }
}

export async function loadHabits() {
  try {
    const fileInfo = await FileSystem.getInfoAsync(HABITS_FILE);
    if (!fileInfo.exists) {
      await ensureDatabase();
      return initialHabits;
    }

    const content = await FileSystem.readAsStringAsync(HABITS_FILE, {
      encoding: FileSystem.EncodingType.UTF8,
    });
    return JSON.parse(content);
  } catch (error) {
    console.error('Error loading habits:', error);
    return initialHabits;
  }
}

export async function saveHabits(habits) {
  try {
    await FileSystem.writeAsStringAsync(
      HABITS_FILE,
      JSON.stringify(habits),
      { encoding: FileSystem.EncodingType.UTF8 }
    );
  } catch (error) {
    console.error('Error saving habits:', error);
    throw error;
  }
}
